prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?choreo ?modelName ?created ?partRef ?participantName WHERE {
  ?org tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:modelCreated ?created ;
         tai:belongsTo ?org .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bboExt:initiatingParticipantRef ?partRef .
  OPTIONAL { ?task bbo:name ?taskName . }

  OPTIONAL {
    ?participant a bboExt:Participant ;
                 tai:belongsTo ?choreo ;
                 bbo:name ?participantName .
    FILTER(STRENDS(STR(?participant), ?partRef))
  }
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?orgId WHERE {
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:modelCreated ?created ;
         tai:belongsTo ?org .
  ?org tai:organizationId ?orgId .
  FILTER(?orgId = "4d36ddb24c9e4cc38572abbd646c1e58")
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?elemType ?elem ?name ?partRef ?participantName WHERE {
  ?model a bboExt:Model ; bbo:name ?modelName ; tai:modelCreated ?created ; tai:belongsTo ?org .
  ?org tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .

  ?choreo a bboExt:Choreography ; tai:belongsTo ?model .

  {
    ?task a ?elemType .
    FILTER(?elemType = bboExt:ChoreographyTask || ?elemType = bboExt:StartEvent || ?elemType = bboExt:IntermediateCatchEvent)
  }

  OPTIONAL { ?task bbo:name ?name }

  OPTIONAL {
    ?task bboExt:initiatingParticipantRef ?partRef .
    FILTER(BOUND(?partRef))
  }

  OPTIONAL {
    ?participant a bboExt:Participant ; tai:belongsTo ?choreo ; bbo:name ?participantName .
    FILTER(BOUND(?partRef) && STRENDS(STR(?participant), ?partRef))
  }
}
ORDER BY ?modelName ?created
LIMIT 25
